import React, { useEffect, useState } from "react";
import { Bar, Pie, Line } from "react-chartjs-2";
import API from "../services/api";

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  LineElement,
  PointElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  LineElement,
  PointElement,
  Title,
  Tooltip,
  Legend
);

function Analytics() {

  const [students, setStudents] = useState([]);

  useEffect(() => {
    fetchStudents();
  }, []);

  const fetchStudents = async () => {
    try {
      const res = await API.get("/students");
      setStudents(res.data);
    } catch (error) {
      console.error("Failed to fetch students", error);
    }
  };

  /* ---------------- KPI CALCULATIONS ---------------- */

  const totalStudents = students.length;

  const placedStudents = students.filter(
    (s) => s.placed === true
  ).length;

  const placementRate =
    totalStudents > 0
      ? ((placedStudents / totalStudents) * 100).toFixed(1)
      : 0;

  const avgCGPA =
    totalStudents > 0
      ? (
          students.reduce((sum, s) => sum + Number(s.cgpa || 0), 0) /
          totalStudents
        ).toFixed(2)
      : 0;

  /* ---------------- BRANCH ANALYTICS ---------------- */

  const branchCount = {};

  students.forEach((s) => {
    if (!branchCount[s.branch]) {
      branchCount[s.branch] = 0;
    }

    if (s.placed) {
      branchCount[s.branch]++;
    }
  });

  const branchData = {
    labels: Object.keys(branchCount),
    datasets: [
      {
        label: "Placed Students",
        data: Object.values(branchCount),
        backgroundColor: "#2563eb",
      },
    ],
  };

  /* ---------------- PIE CHART ---------------- */

  const pieData = {
    labels: ["Placed", "Unplaced"],
    datasets: [
      {
        data: [
          placedStudents,
          totalStudents - placedStudents,
        ],
        backgroundColor: ["#22c55e", "#ef4444"],
      },
    ],
  };

  /* ---------------- SKILL ANALYTICS ---------------- */

  const skillRanges = {
    "50-60": 0,
    "60-70": 0,
    "70-80": 0,
    "80-90": 0,
    "90+": 0,
  };

  students.forEach((s) => {
    const skill = Number(s.skills_score || 0);

    if (skill >= 90) skillRanges["90+"]++;
    else if (skill >= 80) skillRanges["80-90"]++;
    else if (skill >= 70) skillRanges["70-80"]++;
    else if (skill >= 60) skillRanges["60-70"]++;
    else if (skill >= 50) skillRanges["50-60"]++;
  });

  const skillData = {
    labels: Object.keys(skillRanges),
    datasets: [
      {
        label: "Students",
        data: Object.values(skillRanges),
        backgroundColor: "#8b5cf6",
      },
    ],
  };

  /* ---------------- TREND DATA ---------------- */

  const trendData = {
    labels: ["2021", "2022", "2023", "2024"],
    datasets: [
      {
        label: "Placement %",
        data: [58, 62, 70, 74], // you can replace later with real DB data
        borderColor: "#22c55e",
        backgroundColor: "#22c55e",
        tension: 0.4,
      },
    ],
  };

  const options = {
    responsive: true,
    plugins: {
      legend: {
        labels: { color: "white" },
      },
    },
    scales: {
      x: {
        ticks: { color: "white" },
      },
      y: {
        ticks: { color: "white" },
      },
    },
  };

  return (
    <div style={{ padding: "30px", color: "white" }}>

      <h1 style={{ marginBottom: "30px" }}>
        Placement Analytics
      </h1>

      {/* KPI CARDS */}

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(4,1fr)",
          gap: "20px",
          marginBottom: "40px",
        }}
      >

        <div style={cardStyle}>
          <h3>Total Students</h3>
          <p>{totalStudents}</p>
        </div>

        <div style={cardStyle}>
          <h3>Placed Students</h3>
          <p>{placedStudents}</p>
        </div>

        <div style={cardStyle}>
          <h3>Placement Rate</h3>
          <p>{placementRate}%</p>
        </div>

        <div style={cardStyle}>
          <h3>Average CGPA</h3>
          <p>{avgCGPA}</p>
        </div>

      </div>

      {/* ROW 1 */}

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: "30px",
          marginBottom: "40px",
        }}
      >

        <div>
          <Bar data={branchData} options={options} />
        </div>

        <div style={{ width: "350px", margin: "auto" }}>
          <Pie data={pieData} />
        </div>

      </div>

      {/* ROW 2 */}

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: "30px",
        }}
      >

        <div>
          <Bar data={skillData} options={options} />
        </div>

        <div>
          <Line data={trendData} options={options} />
        </div>

      </div>

    </div>
  );
}

const cardStyle = {
  background: "#0f172a",
  padding: "20px",
  borderRadius: "10px",
  textAlign: "center",
  border: "1px solid #1e293b",
};

export default Analytics;
